DO $$ DECLARE r RECORD; idx_name text; BEGIN FOR r IN SELECT c.conrelid::regclass::text as tbl, a.attname as col FROM pg_constraint c JOIN pg_attribute a ON a.attrelid = c.conrelid AND a.attnum = any(c.conkey) WHERE c.contype = 'f' AND c.connamespace = 'public'::regnamespace AND NOT EXISTS ( SELECT 1 FROM pg_index i WHERE i.indrelid = c.conrelid AND a.attnum = any(i.indkey) ) ORDER BY c.conrelid::regclass::text, a.attname LOOP idx_name := 'idx_' || replace(r.tbl, '.', '_') || '_' || r.col; BEGIN EXECUTE format('CREATE INDEX %I ON %s (%I)', idx_name, r.tbl, r.col); RAISE NOTICE 'Created index % on %.%', idx_name, r.tbl, r.col; EXCEPTION WHEN duplicate_table THEN RAISE NOTICE 'Index % already exists, skipping', idx_name; END; END LOOP; END $$;;
